// Rack B – Normal production workload

let cpuLoad = Math.min(100, 35 + Math.random() * 35); // 35–70%
let ambient = 24 + Math.random() * 2;
let inlet = ambient + cpuLoad * 0.06;
let exhaust = inlet + 6 + Math.random() * 2;

const payload = {
  rack_id: "RackB",
  cpu_util: Number(cpuLoad.toFixed(2)),
  power_kw: Number((0.7 + cpuLoad * 0.012).toFixed(2)),
  ambient_temp_c: Number(ambient.toFixed(2)),
  inlet_temp_c: Number(inlet.toFixed(2)),
  exhaust_temp_c: Number(exhaust.toFixed(2)),
  fan_speed_rpm: Math.round(2200 + cpuLoad * 28),
  humidity: Number((44 + Math.random() * 6).toFixed(2))
};

msg.payload =
  "mosquitto_pub -d -q 1 " +
  "-h 192.168.29.21 -p 1883 " +
  "-t v1/devices/me/telemetry " +
  "-u anjutlm67oiegbxbk0h1 " +
  "-m \"" + JSON.stringify(payload).replace(/"/g, '\\"') + "\"";

return msg;
